    ("Repositories",        [("What does helm repo update do?",          "Fetches latest chart index from all configured repos", "Repos publish an index.yaml. helm repo update downloads fresh copies. Without it you may install stale chart versions."),("Search Artifact Hub from CLI?",        "helm search hub <term>",  "helm search hub searches artifacthub.io. helm search repo searches only your locally configured repos."),("helm search repo vs helm search hub?", "repo=local repos only, hub=public artifacthub.io", "hub has 15,000+ charts. repo is faster and searches only repos you've explicitly added with helm repo add.")]),
    ("Releases",            [("What does --atomic do on upgrade?",        "Auto-rollback to previous revision if upgrade fails", "If any resource fails to deploy, Helm rolls back automatically. Combine with --timeout to set max wait time."),("How many revisions kept by default?",  "10 revisions",  "Change with --history-max flag or historyMax in values. Each revision is one Kubernetes Secret."),("helm rollback vs re-running upgrade?", "rollback restores previous manifest; upgrade applies new one", "rollback is instant — it reapplies the stored previous manifest. upgrade runs the full template + apply cycle.")]),
