    ("Build & Dev",         [("Order of env variable precedence?",       "shell env > .env file > compose.yaml environment > image ENV", "Shell environment always wins. Then .env file. Then compose.yaml environment:. Then Dockerfile ENV. Highest to lowest."),("How do anonymous volumes work?",       "Docker creates an unnamed volume, not accessible by name", "- /app/node_modules creates a volume that 'shadows' any bind mount at the parent. Keeps container's node_modules intact."),("Pass a .env file to Compose?",         "--env-file flag or place .env in project root (auto-loaded)", "docker compose --env-file .env.prod up. Compose auto-loads .env in the same dir as compose.yaml.")]),
    ("Networks",            [("Can a container be on multiple networks?","Yes — add it to multiple networks in the service definition", "Under networks: list multiple network names. The container gets a separate IP on each network."),("Give service a custom hostname?",      "hostname: key in the service definition", "The hostname is used for DNS within the network. Other services can reach it by both service name and hostname."),("network_mode: host?",                  "Container shares host network stack — no isolation", "No port mapping needed — container uses host ports directly. No network isolation. Useful for low-latency or monitoring tools.")]),
    ("Volumes",             [("Share a volume between services?",         "Reference the same named volume in both service volume: sections", "Both services must declare the same named volume name. The volume appears in the top-level volumes: section once."),("Named volumes on docker compose down?","Preserved — not deleted", "down only removes containers and networks. Use down -v to also remove named volumes. Intentional to protect data."),("Migrate data between volumes?",        "docker run with both volumes mounted, then copy files", "docker run --rm -v old:/from -v new:/to alpine cp -av /from/. /to/")]),
    ("Health Checks",       [("Four conditions in depends_on?",           "service_started, service_healthy, service_completed_successfully, service_failed", "service_started: container is running. service_healthy: healthcheck passes. service_completed_successfully: exited 0."),("What is start_period in healthcheck?", "Grace period before failed checks count", "During start_period, failing healthchecks don't mark service unhealthy. Useful for slow-starting apps."),("Check health status of a service?",    "docker compose ps shows health column; docker inspect shows Health.Status", "docker inspect --format='{{.State.Health.Status}}' <container> returns: healthy, unhealthy, starting.")]),
    ("Profiles",            [("Use different .env files per environment?","docker compose --env-file .env.prod up", "Combine with -f for full override: docker compose -f compose.yaml -f compose.prod.yaml --env-file .env.prod up -d"),("environment vs env_file in service?",  "environment=inline key-value, env_file=load from file", "environment: sets vars directly in compose.yaml. env_file: reads a file line by line and sets each as an env var."),("Prevent variable expansion in compose?","Use $$ instead of $ to escape", "$$VAR becomes the literal string $VAR in the container instead of being expanded by Compose.")]),
