    ("Data Sources",        [("Pre-provision dashboards on startup?",     "Use provisioning ConfigMaps with dashboards in /var/lib/grafana/dashboards/", "Create a Grafana dashboard provider config pointing to a directory. Mount dashboard JSON files via ConfigMap. They appear automatically."),("Grafana OSS vs Enterprise vs Cloud?", "OSS=free open source, Enterprise=paid RBAC/SSO/plugins, Cloud=hosted SaaS", "OSS has all core features. Enterprise adds LDAP sync, data source permissions, reporting. Cloud is fully managed with generous free tier."),("Reset admin password?",               "grafana-cli admin reset-admin-password <new-password>", "Run inside the Grafana pod: kubectl exec -n monitoring <pod> -- grafana-cli admin reset-admin-password newpass")]),
