    ("Grafana Alloy",       [("Alloy vs Promtail?",                       "Alloy=unified agent (metrics+logs+traces), Promtail=logs only", "Promtail is log-only and being deprecated. Alloy replaces Promtail, Grafana Agent, and can replace OTel Collector in many cases."),("How do Alloy components communicate?", "Via typed references — outputs connect to receivers", "forward_to = [loki.write.default.receiver] passes log entries from one component to another. It's a pipeline graph."),("Debug an Alloy config?",               "alloy run --stability.level=experimental config.river, check /metrics and /-/ready endpoints", "Alloy exposes its own metrics on port 12345. Use the built-in UI at /graph to visualize the component pipeline.")]),
    ("Dashboards as Code",  [("Alternatives to Grafonnet?",               "Grizzly (grr), Terraform Grafana provider, grafana-dashboard-manager", "Grizzly uses YAML/Jsonnet. Terraform provider manages dashboards as infrastructure. All solve the 'dashboards in Git' problem."),("Import dashboard via Grafana API?",    "POST /api/dashboards/db with dashboard JSON", "curl -X POST http://admin:pass@host:3000/api/dashboards/db -H 'Content-Type: application/json' -d @dashboard.json"),("Prevent UI changes overwriting provisioned dashboards?","Set allowUiUpdates: false in dashboard provider config", "With allowUiUpdates: false, the dashboard is read-only in the UI. Changes must be made in the JSON file and reloaded.")]),
    ("Correlation",         [("Configure Exemplars to link metrics to traces?","Enable exemplars in Prometheus and set trace ID label in Grafana data source", "Prometheus scrapes exemplars from apps. In Grafana Prometheus data source, set traceLogsCorrelation with the Tempo data source UID."),("Labels that must match for correlation?","service_name or app label must match between Prometheus and Loki streams", "Grafana uses a label mapping to jump from metric series to log stream. The mapping must use a common label value."),("Set up trace context propagation?",   "Inject W3C TraceContext headers (traceparent) in HTTP requests between services", "Use OTel SDK with propagators: [tracecontext]. Each service reads/writes the traceparent header to maintain the trace ID chain.")]),
    ("OnCall",              [("Grafana OnCall vs PagerDuty?",              "OnCall=open source self-hosted, PagerDuty=paid SaaS", "OnCall has rotations, escalations, Slack/Teams integration. PagerDuty adds analytics, mobile app, and SLA guarantees. OnCall is free for self-hosters."),("Set up follow-the-sun rotation?",     "Create overlapping schedules per timezone, each covering their business hours", "Add schedule 1: EU team Mon-Fri 9-17 CET. Schedule 2: US team Mon-Fri 9-17 EST. They hand off automatically."),("Acknowledge alert from Slack?",        "Click 'Acknowledge' button in the OnCall Slack notification message", "OnCall sends rich Slack messages with action buttons. Acknowledging assigns the alert to you and stops escalation.")]),
    ("Production",          [("Migrate Grafana SQLite to PostgreSQL?",    "Export all content, set GF_DATABASE_TYPE=postgres, reimport", "Use grafana-cli or Grizzly to export dashboards/datasources. Update env vars. On first start with Postgres, reimport everything."),("Grafana Mimir vs Prometheus?",         "Mimir=horizontally scalable Prometheus-compatible backend for massive scale", "Mimir uses object storage (S3) and can handle 10x the metrics of a single Prometheus. Use it when you outgrow Prometheus."),("SAML SSO for Grafana Enterprise?",    "Set GF_AUTH_SAML_ENABLED=true and configure IdP metadata URL in Grafana config", "Grafana Enterprise supports SAML 2.0 with Okta, Azure AD, Auth0. OSS supports OAuth (GitHub, Google, Generic OAuth).")]),
