    ("Labels",              [("Recommended max active streams?",          "Under 10,000 per Loki instance for healthy performance", "Monitor loki_ingester_streams_created_total. Too many streams = high memory + slow queries. Reduce cardinality in labels."),("Add K8s metadata as labels automatically?","Grafana Alloy or Promtail with kubernetes_sd_config does this automatically", "Alloy's loki.source.kubernetes component automatically extracts namespace, pod, container as labels from the K8s API."),("Label vs structured metadata in Loki v3?","Labels=indexed for stream selection, metadata=stored but not indexed", "Structured metadata (OTel attributes) is searchable at query time but doesn't create new streams. Best of both worlds.")]),
    ("OTel Collector",      [("OTel Collector vs Grafana Alloy?",         "Collector=vendor-neutral CNCF standard, Alloy=Grafana-specific with River config", "Alloy supports OTel natively and adds Grafana-specific features. Collector is more portable. Both work well with Loki/Tempo."),("Add sampling to reduce trace volume?", "Use tailsampling or probabilistic_sampler processor in the Collector", "probabilistic_sampler: sampling_percentage: 10 keeps 10% of traces. tail_sampling keeps 100% of error traces."),("What does resourcedetection processor do?","Automatically detects and adds resource attributes (K8s node, cloud provider...)", "Adds metadata like k8s.node.name, cloud.region automatically. Enriches telemetry without changing application code.")]),
    ("Instrumentation",     [("OTel auto-instrumentation languages?",     "Node.js, Python, Java, .NET, Go, PHP, Ruby", "The OTel Operator injects language-specific SDKs as init containers. Just add the annotation to your Deployment."),("Head-based vs tail-based sampling?",   "Head=decision at trace start (fast), Tail=decision after all spans received (accurate)", "Head sampling is simple and low-overhead. Tail sampling can keep 100% of error traces and sample the rest — requires buffering."),("Add custom attributes to a trace?",   "Use the OTel SDK span API: span.setAttribute('key', value)", "const span = tracer.startSpan('operation'); span.setAttribute('user.id', userId); span.end();")]),
