def wrap(c, text, font, size, max_w):
    words = text.split(); cur = ""; lines = []
    for w in words:
        test = (cur + " " + w).strip()
        if stringWidth(test, font, size) <= max_w: cur = test
        else:
            if cur: lines.append(cur)
            cur = w
    if cur: lines.append(cur)
    return lines

def draw_guide_image(c, t, guide_qa):
    """Draw a single 1080x1080 answer key image for one guide."""
    # Background
    c.setFillColor(HexColor("#F8FAFC")); c.rect(0,0,W,H,fill=1,stroke=0)
    # Top header bar
    c.setFillColor(t['d']); c.rect(0,H-90,W,90,fill=1,stroke=0)
    c.setFillColor(t['p']); c.rect(0,H-96,W,6,fill=1,stroke=0)
    # Header text
    c.setFillColor(WHITE); c.setFont("Helvetica-Bold",11)
    c.drawString(30,H-34,"ESSENTIAL TRAINING SERIES  ·  ANSWER KEY")
    c.setFont("Helvetica-Bold",42); c.drawString(30,H-80,t['name'])
    c.setFont("Helvetica-Bold",13)
    c.drawRightString(W-30,H-42,t['version'])
    c.drawRightString(W-30,H-70,"Answer Key — All Exercises")

    # Layout: 2 columns of exercises
    PAD = 28; COL_W = (W - PAD*3) // 2; ROW_H = 112; COLS = 2
    exercises = guide_qa
    n = len(exercises)
    rows = (n + 1) // 2
    start_y = H - 110

    for idx, (ex_title, qas) in enumerate(exercises):
        col = idx % COLS
        row = idx // COLS
        x = PAD + col * (COL_W + PAD)
        y = start_y - row * ROW_H - ROW_H

        # Exercise card bg
        c.setFillColor(WHITE)
        c.roundRect(x, y, COL_W, ROW_H - 6, 8, fill=1, stroke=0)
        c.setStrokeColor(t['m']); c.setLineWidth(1.2)
        c.roundRect(x, y, COL_W, ROW_H - 6, 8, fill=0, stroke=1)
        # Top stripe
        c.setFillColor(t['p'])
        c.roundRect(x, y + ROW_H - 6 - 28, COL_W, 28, 8, fill=1, stroke=0)
        c.rect(x, y + ROW_H - 6 - 14, COL_W, 14, fill=1, stroke=0)
        # Exercise number pill
        c.setFillColor(t['d'])
        c.roundRect(x+8, y + ROW_H - 6 - 24, 26, 18, 4, fill=1, stroke=0)
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold",9)
        c.drawCentredString(x+21, y + ROW_H - 6 - 18, f"{idx+1:02d}")
        # Exercise title
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold",11)
        title_w = COL_W - 52
        title_lines = wrap(c, ex_title, "Helvetica-Bold", 11, title_w)
        c.drawString(x+42, y + ROW_H - 6 - 18, title_lines[0] if title_lines else ex_title)

        # Q&A items
        inner_y = y + ROW_H - 40
        for qi, (q_text, ans, expl) in enumerate(qas[:3]):
            inner_y -= 4
            # Tiny Q bullet
            c.setFillColor(t['m']); c.circle(x+14, inner_y+3, 4, fill=1, stroke=0)
            c.setFillColor(WHITE); c.setFont("Helvetica-Bold",5.5)
            c.drawCentredString(x+14, inner_y+1, "Q")
            # Question (truncated)
            q_short = q_text if len(q_text) <= 48 else q_text[:46]+"…"
            c.setFillColor(HexColor("#374151")); c.setFont("Helvetica-Bold",8.5)
            c.drawString(x+24, inner_y+1, q_short)
            inner_y -= 14
            # Answer
            c.setFillColor(HexColor("#15803D")); c.setFont("Helvetica-Bold",8.5)
            ans_short = ans if len(ans) <= 62 else ans[:60]+"…"
            c.drawString(x+24, inner_y+1, "→ "+ans_short)
            inner_y -= 13
            # Explanation
            c.setFillColor(GRAY); c.setFont("Helvetica-Oblique",7.5)
            ex_short = expl if len(expl) <= 75 else expl[:73]+"…"
            c.drawString(x+24, inner_y+1, ex_short)
            inner_y -= 4

    # Bottom bar
    c.setFillColor(t['d']); c.rect(0,0,W,44,fill=1,stroke=0)
    c.setFillColor(t['p']); c.rect(0,44,W,4,fill=1,stroke=0)
    c.setFillColor(WHITE); c.setFont("Helvetica-Bold",12)
    c.drawString(30,16,f"{t['name']} Essential Training — Answer Key  ·  {t['version']}")
    c.setFont("Helvetica",10)
    c.drawRightString(W-30,16,"#DevOps  #Kubernetes  #CloudNative")

# Build all 10 images
guide_order = ["k3s","docker","helm","k8s","compose","actions","argocd","prom","grafana","loki"]
file_names  = ["K3s","Docker","Helm","Kubernetes","DockerCompose","GitHubActions","ArgoCD","Prometheus","Grafana","Loki_OpenTelemetry"]

for key, fname in zip(guide_order, file_names):
    t = GUIDES[key]
    qa = QA_DATA[key]
    out = f"{OUT}/{fname}_AnswerKey.pdf"
    c = canvas.Canvas(out, pagesize=(W,H))
    draw_guide_image(c, t, qa)
    c.showPage(); c.save()
    print(f"✓ {out}")

print("\n✅ All 10 answer key images generated!")
